"use client";
import React from "react";
import { useState, useEffect, useCallback } from "react";
import Select from "../Select/Select";
import css from "./FiltersBar.module.css";
import { fetchBrands } from "../../lib/api/clientApi";

const priceOptions = ["30", "40", "50", "60", "70", "80"];

type Props = {
  filters: any; 
  onSearch: (filters: any) => void;
};

export default function FilterBar({ filters, onSearch }: Props) {
  const [brands, setBrands] = useState<string[]>([]);
  const [localFilters, setLocalFilters] = useState(filters);
  const [debouncedFilters, setDebouncedFilters] = useState(filters);

  // Синхронiзацiя с props
  useEffect(() => {
    setLocalFilters(filters);
    setDebouncedFilters(filters);
  }, [filters]);

  // бренд
  useEffect(() => {
    fetchBrands().then(setBrands);
  }, []);

  // Debounce
  useEffect(() => {
    const timer = setTimeout(() => {
      onSearch(debouncedFilters);
    }, 500);

    return () => clearTimeout(timer);
  }, [debouncedFilters, onSearch]);

  const updateFilter = useCallback((key: string, value: string) => {
    setLocalFilters((prev: any) => ({ ...prev, [key]: value }));
    setDebouncedFilters((prev: any) => ({ ...prev, [key]: value }));
  }, []);

  return (
    <div className={css.container}>
      {/* Car brand */}
      <div>
        <p className={css.params}>Car brand</p>
        <Select
          options={brands}
          value={localFilters.brand}
          onChange={(v) => updateFilter("brand", v)}
          placeholder="Choose a brand"
        />
      </div>

      {/* Price */}
      <div>
        <p className={css.params}>Price / 1 hour</p>
        <Select
          options={priceOptions}
          value={localFilters.rentalPrice}
          onChange={(v) => updateFilter("rentalPrice", v)}
          placeholder="Choose a price"
        />
      </div>

      {/* Mileage */}
      <div>
        <p className={css.params}>Car mileage / km</p>
        <div className={css.doubleInput}>
          <input
            placeholder="From"
            value={localFilters.minMileage || ""}
            onChange={(e) => updateFilter("minMileage", e.target.value)}
            className={css.inputField}
            type="number"
            min="0"
          />
          <div className={css.separator}></div>
          <input
            placeholder="To"
            value={localFilters.maxMileage || ""}
            onChange={(e) => updateFilter("maxMileage", e.target.value)}
            className={css.inputField}
            type="number"
            min="0"
          />
        </div>
      </div>

      {/* Search */}
      <button 
        onClick={() => onSearch(localFilters)} 
        className={css.button}
      >
        Search
      </button>
    </div>
  );
}
